const response = $input.first().json;

// Handle case where no vendors are due
const vendors = Array.isArray(response) ? response : [];

if (vendors.length === 0) {
  return [{ json: { has_vendors: false, vendor_count: 0, message: 'No vendors due for sync' } }];
}

// Return each vendor as a separate item for the loop
return vendors.map(v => ({ json: {
  has_vendors: true,
  vendor_count: vendors.length,
  vendor_id: v.id,
  vendor_name: v.name || 'Unknown',
  vendor_email: v.email || null,
  source_type: v.source_type || 'manual',
  source_config: typeof v.source_config === 'string' ? JSON.parse(v.source_config) : (v.source_config || {}),
  marketplace_url: v.marketplace_url || null,
  marketplace_api_key: v.marketplace_api_key || null,
  sync_interval_minutes: v.sync_interval_minutes || 60,
  last_sync_at: v.last_sync_at
} }));

const vendor = $input.first().json;
const config = vendor.source_config;

// Build Shopify API request to fetch products
const shopifyDomain = config.shop_domain || config.domain;
const accessToken = config.access_token || config.api_key;
const sinceDate = vendor.last_sync_at || null;

if (!shopifyDomain || !accessToken) {
  return [{ json: {
    sync_success: false,
    vendor_id: vendor.vendor_id,
    vendor_name: vendor.vendor_name,
    source_type: 'shopify',
    error: 'Missing Shopify configuration (shop_domain or access_token)',
    products: [],
    product_count: 0
  } }];
}

// We'll construct the URL for fetching products
let url = `https://${shopifyDomain}/admin/api/2024-01/products.json?limit=250&status=active`;
if (sinceDate) {
  url += `&updated_at_min=${sinceDate}`;
}

return [{ json: {
  vendor_id: vendor.vendor_id,
  vendor_name: vendor.vendor_name,
  vendor_email: vendor.vendor_email,
  source_type: 'shopify',
  fetch_url: url,
  access_token: accessToken,
  marketplace_url: vendor.marketplace_url,
  marketplace_api_key: vendor.marketplace_api_key,
  sync_interval_minutes: vendor.sync_interval_minutes
} }];

const vendor = $input.first().json;
const config = vendor.source_config;

// Build WooCommerce API request
const siteUrl = config.site_url || config.url;
const consumerKey = config.consumer_key;
const consumerSecret = config.consumer_secret;
const sinceDate = vendor.last_sync_at || null;

if (!siteUrl || !consumerKey || !consumerSecret) {
  return [{ json: {
    sync_success: false,
    vendor_id: vendor.vendor_id,
    vendor_name: vendor.vendor_name,
    source_type: 'woocommerce',
    error: 'Missing WooCommerce configuration (site_url, consumer_key, or consumer_secret)',
    products: [],
    product_count: 0
  } }];
}

let url = `${siteUrl.replace(/\/$/, '')}/wp-json/wc/v3/products?per_page=100&status=publish`;
if (sinceDate) {
  url += `&modified_after=${sinceDate}`;
}

// WooCommerce uses Basic auth with consumer key/secret
const authHeader = 'Basic ' + Buffer.from(`${consumerKey}:${consumerSecret}`).toString('base64');

return [{ json: {
  vendor_id: vendor.vendor_id,
  vendor_name: vendor.vendor_name,
  vendor_email: vendor.vendor_email,
  source_type: 'woocommerce',
  fetch_url: url,
  auth_header: authHeader,
  marketplace_url: vendor.marketplace_url,
  marketplace_api_key: vendor.marketplace_api_key,
  sync_interval_minutes: vendor.sync_interval_minutes
} }];

const vendor = $input.first().json;
const config = vendor.source_config;

// Custom API sync
const apiUrl = config.api_url || config.endpoint;
const apiHeaders = config.headers || {};
const apiMethod = (config.method || 'GET').toUpperCase();

if (!apiUrl) {
  return [{ json: {
    sync_success: false,
    vendor_id: vendor.vendor_id,
    vendor_name: vendor.vendor_name,
    source_type: 'api',
    error: 'Missing API configuration (api_url)',
    products: [],
    product_count: 0
  } }];
}

return [{ json: {
  vendor_id: vendor.vendor_id,
  vendor_name: vendor.vendor_name,
  vendor_email: vendor.vendor_email,
  source_type: 'api',
  fetch_url: apiUrl,
  api_headers: apiHeaders,
  api_method: apiMethod,
  marketplace_url: vendor.marketplace_url,
  marketplace_api_key: vendor.marketplace_api_key,
  sync_interval_minutes: vendor.sync_interval_minutes
} }];

const vendor = $input.first().json;

// Manual/unknown source type - skip sync but update timestamps
return [{ json: {
  sync_success: true,
  vendor_id: vendor.vendor_id,
  vendor_name: vendor.vendor_name,
  source_type: vendor.source_type || 'manual',
  skipped: true,
  message: `Skipping sync for source type '${vendor.source_type || 'manual'}' - manual upload only`,
  products: [],
  product_count: 0,
  sync_interval_minutes: vendor.sync_interval_minutes
} }];

const input = $input.first().json;
const prevNode = $('Prepare Shopify Sync').first().json;

const statusCode = input.statusCode || input.status;
if (!statusCode || statusCode < 200 || statusCode >= 300) {
  return [{ json: {
    sync_success: false,
    vendor_id: prevNode.vendor_id,
    vendor_name: prevNode.vendor_name,
    source_type: 'shopify',
    error: `Shopify API returned ${statusCode}: ${input.body?.errors || input.message || 'Unknown error'}`,
    products: [],
    product_count: 0,
    sync_interval_minutes: prevNode.sync_interval_minutes
  } }];
}

const body = input.body || input;
const products = body.products || [];

return [{ json: {
  sync_success: true,
  vendor_id: prevNode.vendor_id,
  vendor_name: prevNode.vendor_name,
  source_type: 'shopify',
  products: products,
  product_count: products.length,
  sync_interval_minutes: prevNode.sync_interval_minutes
} }];

const input = $input.first().json;
const prevNode = $('Prepare WooCommerce Sync').first().json;

const statusCode = input.statusCode || input.status;
if (!statusCode || statusCode < 200 || statusCode >= 300) {
  return [{ json: {
    sync_success: false,
    vendor_id: prevNode.vendor_id,
    vendor_name: prevNode.vendor_name,
    source_type: 'woocommerce',
    error: `WooCommerce API returned ${statusCode}: ${input.body?.message || input.message || 'Unknown error'}`,
    products: [],
    product_count: 0,
    sync_interval_minutes: prevNode.sync_interval_minutes
  } }];
}

const body = input.body || input;
const products = Array.isArray(body) ? body : (body.products || []);

return [{ json: {
  sync_success: true,
  vendor_id: prevNode.vendor_id,
  vendor_name: prevNode.vendor_name,
  source_type: 'woocommerce',
  products: products,
  product_count: products.length,
  sync_interval_minutes: prevNode.sync_interval_minutes
} }];

const input = $input.first().json;
const prevNode = $('Prepare API Sync').first().json;

const statusCode = input.statusCode || input.status;
if (!statusCode || statusCode < 200 || statusCode >= 300) {
  return [{ json: {
    sync_success: false,
    vendor_id: prevNode.vendor_id,
    vendor_name: prevNode.vendor_name,
    source_type: 'api',
    error: `API returned ${statusCode}: ${input.body?.message || input.message || 'Unknown error'}`,
    products: [],
    product_count: 0,
    sync_interval_minutes: prevNode.sync_interval_minutes
  } }];
}

const body = input.body || input;
// Try common response patterns
const products = Array.isArray(body) ? body : (body.products || body.items || body.data || []);

return [{ json: {
  sync_success: true,
  vendor_id: prevNode.vendor_id,
  vendor_name: prevNode.vendor_name,
  source_type: 'api',
  products: products,
  product_count: Array.isArray(products) ? products.length : 0,
  sync_interval_minutes: prevNode.sync_interval_minutes
} }];

const input = $input.first().json;
const now = new Date();
const interval = input.sync_interval_minutes || 60;
const next_sync_at = new Date(now.getTime() + interval * 60 * 1000).toISOString();

return [{ json: {
  ...input,
  last_sync_at: now.toISOString(),
  next_sync_at,
  sync_completed: true
} }];
